import React from 'react'


const ModalV2 = ({ isShown, setIsShown, children }) => {

  return (
    <div
      className={(!isShown ? 'hidden ' : '') + 'p-5 bg-[#0000009c] overflow-x-hidden  overflow-y-auto fixed top-0 left-0 w-screen h-screen z-50 overflow-scroll'}
      onClick={(e) => e.currentTarget === e.target && setIsShown(false)}>


      <div className='bg-gray-900 rounded-md p-5 max-w-xl mx-auto'>

        {children}

      </div>
    </div>
  )
}

export default ModalV2