import React, { useEffect, useState } from 'react'
import IonIcon from '@reacticons/ionicons';
import { useNavigate, useParams } from 'react-router-dom';

// Project Imports
import Loader from '../utils/Loader'
import InputFile from '../utils/InputFile';
import Input from '../utils/Input';
import Select from '../utils/Select';
import { fetchData } from '../../functions/fetchData'
import Button from '../utils/Button';
import urls from '../../constants/urls';
import { postData } from '../../functions/postData';

const AbsenceForm = () => {

  const navigate = useNavigate()
  const params = useParams()

  const [_isLoading, setLoading] = useState(false);
  const [isFormCompleted, setFormCompleted] = useState(false);
  const [absenceTypes, setAbsenceTypes] = useState([]);
  const [formData, setFormData] = useState({
    absence_type: undefined,
    attachement: undefined,
    observation: ""
  })



  useEffect(() => {
    fetchData(
      urls.ABSENCE_TYPES,
      (data) => {
        setAbsenceTypes(data)
        if (data.length > 0)
          setFormField({ absence_type: data[0].id })
      },
      setLoading)

  }, [absenceTypes.length])


  const onSubmit = () => {
    const data = new FormData();
    
    for (const [key, value] of Object.entries(formData)) {
      data.append(key, value);
    }
    

    postData(
      urls.ABSENCE_FILE_UPLOAD(params.id),
      'PUT',
      {
        'Content-Type': 'multipart/form-data'
      },
      data,
      setLoading,
      () => navigate('/'),
      () => setLoading(false)
    )
  }


  const setFormField = (field) => {
    setFormData(
      {
        ...formData,
        ...field
      }
    )
  }

  const checkForm = () => {
    let isFormCompleted_ = true
    if (!formData.attachement || !formData.absence_type)
      isFormCompleted_ = false
    else
      isFormCompleted_ = true

    isFormCompleted_ !== isFormCompleted && setFormCompleted(isFormCompleted_)
  }

  checkForm()

  return (
    <div className='bg-gray-900 text-gray-100 min-h-screen'>
      <header className="flex items-center content-between py-3 px-3 bg-black">
        <div className='flex flex-1 items-center'>
          <IonIcon className='py-3 pr-3 text-2xl' name='chevron-back' onClick={() => navigate(-1)} />
          <h3 className='text-xl'>Justification d'Absence</h3>
        </div>
        {
          _isLoading
            &&
            <Loader />
          
        }
      </header>


      <div className="flex flex-col px-3 gap-5 bg-black pb-5">
        <Select
          label="Raison"
          options={
            absenceTypes.map((type) => ({ value: type.id, name: type.description }))
          }
          onChange={(reason) => setFormField({ absence_type: reason })} />

        <InputFile label="Justificatif" value={formData.attachement} onChange={(event) => setFormField({ attachement: event.target.files[0] })} />

        <Input label="Observation" placeholder='Tapez une observation si nécessaire' onChange={(event) => setFormField({ observation: event.target.value })} />

        <Button label='Valider' onClick={onSubmit} disabled={!isFormCompleted} />


      </div>

    </div>
  )
}

export default AbsenceForm