import React, { useState } from "react";
import { formatDate } from "../../functions/dateUtils";
import ModalDatePicker from "./ModalDatePicker";

const DatePicker = ({ date = new Date(), setDate, className, label }) => {
  const [isShown, setIsShown] = useState(false);

  return (
    <>
      <ModalDatePicker
        isShown={isShown}
        setIsShown={setIsShown}
        date={date}
        setDate={setDate}
        label={label}
      />
      <div
        className={`bg-white text-sm cursor-pointer p-2 rounded-md ${className}`}
        onClick={() => setIsShown(true)}
        style={{ border: "1px solid green" }} // Style pour la bordure verte
      >
        <p className="text-[15px] text-black upper">{label}</p>
        <p className="text-[15px] text-black upper">{formatDate(date)}</p>
      </div>
    </>
  );
};

export default DatePicker;
