import axios from "axios";

export const postData = async (
  url,
  method,
  headers = {},
  body = {},
  loading_state,
  on_success,
  on_error
) => {
  // Setting Loading State
  loading_state(true);

  axios({
    url: url,
    method: method,
    data: body,
    headers: headers
      ? headers
      : {
          "Content-Type": "application/json",
        },
  })
    .then((res) => {
      on_success();
    })
    .catch((err) => {
      if (err.response) {
        const status = err.response.status;
        switch (status) {
          case 400:
            alert(
              "Le Jour de début doit être différent du jour de reprise.\n يجب أن يكون يوم بدء الإجازة مختلفًا عن يوم العودة للعمل "
            );
            break;
          case 410:
            alert(
              "Vous avez déja une absence pour la date choisie, veuillez introduire une autre date.\n لديك غياب  في التاريخ المحدد، يرجى إدخال تاريخ آخر"
            );
            break;
          case 420:
            alert(
              "Vous avez déja un congé introduit pour la date choisie, veuillez introduire une autre date.\n لديك إجازة مُدخلة بالفعل للتاريخ المحدد، يرجى إدخال تاريخ آخر"
            );
            break;
          case 430:
            alert(
              "Vous ne pouvez pas introduire une demande de congé pour une date précedente, veuillez introduire une autre date.\n لا يمكنك إدخال طلب إجازة لتاريخ سابق، يرجى إدخال تاريخ آخر"
            );
            break;
          case 440:
            alert(
              "ATTENTION : Date de début du congé est supérieure à la date de reprise .\n  تنبيه : تاريخ بدء الإجازة بعد تاريخ العودة"
            );
            break;
          default:
            alert("Une erreur s'est produite. Veuillez réessayer.");
        }
      } else {
        alert("Une erreur s'est produite. Veuillez réessayer.");
      }
    })
    .finally(() => loading_state(false));
};
