import React from "react";
import IonIcon from "@reacticons/ionicons";

// Project Imports
import { formatDate } from "../../functions/dateUtils";
import { useNavigate } from "react-router-dom";

const LeaveSingle = ({ leave, onClick }) => {
  // Navigation
  const navigate = useNavigate();

  return (
    <div
      className="flex flex-col relative px-3 py-4 rounded-md bg-white cursor-pointer"
      style={{ border: "2px solid green" }} // Style pour la bordure verte
      onClick={onClick}
    >
      <div className="flex justify-between items-start">
        <div className="text-lg font-medium mb-5">
          <>
            <IonIcon className="text-2xl text-yellow-500" name="time" />
            <div className="text-xl text-black">
              {leave.leave_type.description}
            </div>
            <div className="flex items-center gap-1">
              <div className="text-s text-green-700">{leave.user}</div>
            </div>
          </>
        </div>

        <div className="flex items-center text-xs bg-green-700 gap-1 px-2 py-1 rounded-md uppercase">
          {leave.approved === "ACCEPTED" && (
            <div className="flex items-center text-xs text-white gap-1">
              <IonIcon className="text-xl " name="checkmark" />
              Acceptée
            </div>
          )}
          {leave.approved === "REFUSED" && (
            <>
              <IonIcon className="text-xl text-red-500" name="close" />
              Refusée
            </>
          )}
          {leave.approved === "WAITING" && (
            <>
              <IonIcon className="text-xl text-yellow-500" name="time" />
              En Verification
            </>
          )}
        </div>
      </div>

      <div className="grid grid-cols-2 gap-x-10 gap-y-1">
        <div className="text-xs text-black d-block">
          <p>Date de Début</p>
          <p>تاريخ بداية الإجازة</p>
        </div>
        <div className="text-xs text-black d-block">
          <p>Date de Reprise</p>
          <p> تاريخ العودة للعمل</p>
        </div>
        <div className="text-s text-black">{formatDate(leave.start_date)}</div>
        <div className="text-s text-black">{formatDate(leave.end_date)}</div>
      </div>

      {leave.approved === "ACCEPTED" && (
        <div className="hidden md:block md:absolute md:bottom-2 md:right-3 ">
          <IonIcon
            className="text-2xl p-3 cursor-pointer bg-green-700 rounded-full"
            name="print"
            color="white"
            onClick={(e) =>
              e.currentTarget === e.target &&
              navigate(`/leave/print/${leave.id}`)
            }
          />
        </div>
      )}
    </div>
  );
};

export default LeaveSingle;
