const Button = ({ label, onClick, disabled=false }) => {
  return (
    <button
      type="button"
      onClick={() => onClick()}
      className="text-xs bg-green-700 font-bold py-3 pl-3 rounded-md uppercase disabled:opacity-50" 
      disabled={disabled}
      >
      {label}
    
    </button>
  )
}

export default Button