import { useEffect, useState } from "react"
import axios from "axios"

const useFetch=(default_value="",request,resolve=()=>{},reject=()=>{})=>{
    const [_value, set_value] = useState(default_value)

    const [_is_loading, set_is_loading] = useState(false)

    // const axios=require("axios");


    const get_data=async()=>{
        
        if(!_is_loading)
        {
          set_is_loading(true)
          await axios(request)
          .then(res=>{
            set_is_loading(false)
            set_value(res.data)
            resolve(res)
          })
          .catch(err=>{
            set_is_loading(false)
            reject(err)
            setTimeout(()=>get_data(),5000)
            console.log("use fetch error *********",err)
          })
        }
    }
    useEffect(() => {
      get_data()
      return () => {
        
      }
    }, [])
    
    return  [_value, set_value]
}

export default useFetch