export function ParseDate(string, time_included=false) {
  const date = new Date(string)

  if (time_included)
    return date

  // Returning Date Only
  return new Date(date.getFullYear(), date.getMonth(), date.getDate())
}

export function Today(time_included=false) {
  const date = new Date()

  if (time_included)
    return date

  // Returning Date Only
  return new Date(date.getFullYear(), date.getMonth(), date.getDate())
}


export function DateDifference(dateObject1, dateObject2) {
  const difference = Math.abs(dateObject2 - dateObject1)

  return {
    'seconds': Math.round(difference / 1000),
    'minutes': Math.round(difference / (1000 * 60)),
    'hours': Math.round(difference / (1000 * 60 * 60)),
    'days': Math.round(difference / (1000 * 60 * 60 * 24)),
    'months': Math.round(difference / (1000 * 60 * 60 * 24 * 30)),
    'years': Math.round(difference / (1000 * 60 * 60 * 24 * 30 * 12)),
  }
}

export const get_day_name = (dt) => {
  const language = 'fr-fr';
  const options = { weekday: 'long' };
  const today = new Date(parseInt(dt.split("-")[0]), parseInt(dt.split("-")[1]) - 1, parseInt(dt.split("-")[2])).toLocaleString(language, options)
  return today
}


export const get_month_name = (index) => {
  const fr_months = ['Janvier', 'Février', 'Mars', 'Avril', 'Mai', 'Juin', 'Juillet', 'Août', 'Septembre', 'Octobre', 'Novembre', 'Décembre']
  return fr_months[index]
}

export const formatDate = (date, standard = false) => {
  // Standard returns -> YYYY-MM-dd
  if (typeof (date) === "string")
    date = new Date(date)

  if (standard)
    return `${date.getFullYear()}-${date.getMonth() + 1}-${date.getDate()}`

  return `${date.getDate()} ${get_month_name(date.getMonth())} ${date.getFullYear()}`
}

export const deltaDays = (date, days) => {
  let deltaDate = date
  deltaDate.setDate(date.getDate() + days)
  return deltaDate
}

