import React, { useEffect, useState } from "react";
import IonIcon from "@reacticons/ionicons";
import { useLocation, useNavigate, useParams } from "react-router-dom";

// Project Imports
import Loader from "../utils/Loader";
import InputFile from "../utils/InputFile";
import Input from "../utils/Input";
import Select from "../utils/Selectv2";
import { fetchData } from "../../functions/fetchData";
import Button from "../utils/Button";
import urls from "../../constants/urls";
import { postData } from "../../functions/postData";
import InputDatePicker from "../utils/InputDatePicker";
import { deltaDays, formatDate, Today } from "../../functions/dateUtils";
import imageCompression from "browser-image-compression";

const LeaveForm = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const users = location.state;

  const [_isLoading, setLoading] = useState(false);
  const [isFormCompleted, setFormCompleted] = useState(false);
  const [leaveTypes, setleaveTypes] = useState([]);
  const [formData, setFormData] = useState({
    leave_type: undefined,
    attachement: undefined,
    observation: "",
    address: "",
    start_date: deltaDays(new Date(), 1),
    end_date: deltaDays(new Date(), 7),
    username: users.username,
  });

  useEffect(() => {
    fetchData(
      urls.LEAVE_TYPES,
      (data) => {
        setleaveTypes(data);
      },
      setLoading
    );
  }, [leaveTypes.length]);

  const onSubmit = () => {
    const data = new FormData();

    for (const [key, value] of Object.entries(formData)) {
      data.append(key, value);
    }

    postData(
      urls.LEAVE_FILE_UPLOAD,
      "PUT",
      {
        "Content-Type": "multipart/form-data",
      },
      {
        ...formData,
        start_date: formatDate(formData.start_date, true),
        end_date: formatDate(formData.end_date, true),
      },
      setLoading,
      () => navigate("/"),
      () => setLoading(false)
    );
  };

  const setFormField = (field) => {
    setFormData({
      ...formData,
      ...field,
    });
  };

  const isSuperUser = () => users.is_superuser;

  const checkForm = () => {
    let isFormCompleted_ = true;

    if (
      !formData.leave_type ||
      // formData.start_date > formData.end_date ||
      !formData.username
    )
      isFormCompleted_ = false;
    else isFormCompleted_ = true;

    isFormCompleted_ !== isFormCompleted && setFormCompleted(isFormCompleted_);
  };

  checkForm();

  const handleImageUpload = async (event) => {
    const file = event.target.files[0];

    if (file) {
      try {
        // Compression options
        const options = {
          maxSizeMB: 1, // Limit to 1 MB
          maxWidthOrHeight: 1920, // Resize dimensions
          useWebWorker: true, // Use web worker for performance
        };

        // Compress the image
        const compressedFile = await imageCompression(file, options);

        console.log("Original file size:", file.size / 1024 / 1024, "MB");
        console.log(
          "Compressed file size:",
          compressedFile.size / 1024 / 1024,
          "MB"
        );

        // Create a new File object to preserve the name and type
        const newFile = new File([compressedFile], file.name, {
          type: file.type,
          lastModified: Date.now(),
        });

        // Set the compressed image with the original file name and type, while preserving other form data
        setFormData((prevData) => ({
          ...prevData,
          attachement: newFile,
        }));
      } catch (error) {
        console.error("Image compression error:", error);
      }
    }
  };

  return (
    <div className="bg-white text-gray-100 min-h-screen">
      <header className="flex items-center content-between py-3 px-3 bg-white">
        <div className="flex flex-1 items-center text-black">
          <IonIcon
            className="py-3 pr-3 text-2xl"
            name="chevron-back"
            onClick={() => navigate(-1)}
          />
          <h3 className="text-xl">Demande de Congé | طلب إجازة</h3>
        </div>
        {_isLoading && <Loader />}
      </header>

      <div className="flex flex-col px-3 gap-5 bg-white pb-5 text-black">
        <Select
          label={
            <strong style={{ color: "black" }}>Utilisateur | إسم الموظف</strong>
          }
          className="flex-1"
          placeholder={formData.username}
          options={[
            { label: users.username, value: users.username },
            ...users.users_under.map((usr) => ({
              label: usr.username,
              value: usr.username,
            })),
          ]}
          onChange={(user) => setFormField({ username: user.value })}
        />

        <InputDatePicker
          label={
            <strong style={{ color: "black" }}>
              Date de Début | تبدأ الإجازة من صباح يوم
            </strong>
          }
          date={formData.start_date}
          setDate={(date) => setFormField({ start_date: date })}
        />

        <InputDatePicker
          label={
            <strong style={{ color: "black" }}>
              Date de Reprise | تاريخ العودة للعمل صباح يوم
            </strong>
          }
          date={formData.end_date}
          setDate={(date) => setFormField({ end_date: date })}
        />

        <Select
          label={<strong style={{ color: "black" }}>Type | نوع الإجازة</strong>}
          className="flex-1"
          placeholder="Selectionnez le type du congé"
          options={leaveTypes.map((type) => ({
            value: type.id,
            label: type.description,
          }))}
          onChange={(reason) => setFormField({ leave_type: reason.value })}
        />

        <InputFile
          label={
            <strong style={{ color: "black" }}>
              Justificatif | الورقة الثبوتية
            </strong>
          }
          accept="image/*"
          value={formData.attachement}
          onChange={handleImageUpload}
        />

        {/* <label>
          <strong style={{ color: "black" }}>
            Justificatif | الورقة الثبوتية
          </strong>
          <input type="file" accept="image/*" onChange={handleImageUpload} />
        </label> */}

        <Input
          label={
            <strong style={{ color: "black" }}>
              Adresse | العنوان أثناء الإجازة
            </strong>
          }
          onChange={(event) => setFormField({ address: event.target.value })}
        />

        <Input
          label={
            <strong style={{ color: "black" }}>
              Observation | ملاحظات أخرى للإجازة
            </strong>
          }
          placeholder="Tapez une observation si nécessaire"
          onChange={(event) =>
            setFormField({ observation: event.target.value })
          }
          style={{ color: "white" }}
        />

        <Button
          label={
            <strong style={{ color: "white" }}>Valider | تقديم الطلب</strong>
          }
          onClick={onSubmit}
          disabled={!isFormCompleted}
        />
      </div>
    </div>
  );
};

export default LeaveForm;
