import React from 'react'


export default function Select({ label, options, onChange, multilple = false }) {
  return (
    <div className='flex flex-col text-sm text-gray-200'>
      <label className='capitalize'>{label}</label>
      <select
        className='p-3 h-10 mt-2 rounded-md bg-gray-900 text-white input'
        multiple={multilple}

        style={{ maxHeight: multilple ? window.innerWidth > 600 ? "auto" : "40px" : "auto" }}
        onChange={(event) => onChange(event.target.value)}>
        {
          options.map((option, index) =>
            <option key={index} value={option.value}>{option.name}</option>
          )
        }
      </select>
    </div>
  )
}
