import React, { useState } from "react";

import ModalV2 from "../utils/Modalv2";
import { formatDate } from "../../functions/dateUtils";
import { OpenLink } from "../../functions/webViewUtils";
import { postData } from "../../functions/postData";

import IonIcon from "@reacticons/ionicons";

import urls from "../../constants/urls";
import { Navigate, useNavigate } from "react-router-dom";

const LeaveDetails = ({
  leave,
  isShown,
  setIsShown,
  currentUser,
  onSuccess,
  onFail,
}) => {
  // Navigation
  const navigate = useNavigate();

  const [is_loading, set_is_loading] = useState(false);

  const canValidate = () => {
    return (
      leave.approved === "WAITING" &&
      currentUser.permissions.includes("approve_absence")
    );
  };

  const canEdit = () => {
    return currentUser.permissions.includes("approve_absence");
  };

  const validate = (status) => {
    set_is_loading(true);

    postData(
      urls.LEAVE(leave.id),
      "PUT",
      {},
      {
        approved: status,
      },
      set_is_loading,
      () => {
        set_is_loading(false);
        setIsShown(false);
        onSuccess();
      },
      () => {
        set_is_loading(false);
        onFail();
      }
    );
  };

  const onEditClick = () => {
    OpenLink(urls.LEAVE_ADMIN_EDIT(leave.id), true);
  };

  const Component = () => {
    return (
      <>
        <div className="flex justify-between items-center mb-5">
          {leave.leave_type ? (
            <div className="text-xl font-medium">
              {leave.leave_type.description}
            </div>
          ) : (
            <div className="text-xl font-medium">Absence</div>
          )}
          {canEdit() && (
            <div
              className="flex items-center gap-2 text-xs font-bold p-2 bg-black rounded-md uppercase cursor-pointer"
              onClick={onEditClick}
            >
              <IonIcon className="text-xl" name="create" />
              Modifier
            </div>
          )}
        </div>

        <div className="text-sm mb-3 mt-7">Status</div>

        <div className="grid grid-cols-2 items-center gap-x-10 gap-y-5 bg-black p-4 rounded-md">
          <div className="text-xs text-gray-500">Approbation</div>

          {leave.approved === "ACCEPTED" && (
            <div className="flex items-center gap-2 text-xs text-green-600">
              Acceptée
              <IonIcon className="text-sm" name="checkmark" />
            </div>
          )}
          {leave.approved === "REFUSED" && (
            <div className="flex items-center gap-2 text-xs text-red-600">
              Refusée
              <IonIcon className="text-sm" name="close" />
            </div>
          )}
          {leave.approved === "WAITING" && (
            <div className="flex items-center gap-2 text-xs text-yellow-600">
              En Verification
              <IonIcon className="text-sm" name="time" />
            </div>
          )}

          <div className="text-xs text-gray-500">Auteur</div>
          <div className="text-xs text-gray-300">{leave.author}</div>

          <div className="text-xs text-gray-500">Validé Par</div>
          <div className="text-xs text-gray-300">{leave.approval_user}</div>

          <div className="text-xs text-gray-500">Validé le</div>
          <div className="text-xs text-gray-300">
            {leave.approval_date ? leave.approval_date : "-"}
          </div>
        </div>

        <div className="text-sm mb-3 mt-7">Information Générales</div>

        <div className="grid grid-cols-2 gap-x-10 gap-y-5 bg-black p-4 rounded-md">
          <div className="text-xs text-gray-500">Date de Début</div>
          <div className="text-xs text-gray-300">
            {formatDate(leave.start_date)}
          </div>
          <div className="text-xs text-gray-500">Date de Fin</div>
          <div className="text-xs text-gray-300">
            {formatDate(leave.end_date)}
          </div>
          <div className="text-xs text-gray-500">Utilisateur</div>
          <div className="text-xs text-gray-300">{leave.user}</div>
          <div className="text-xs text-gray-500">Adresse</div>
          <div className="text-xs text-gray-300">
            {leave.address ? leave.address : "-"}
          </div>
          <div className="text-xs text-gray-500">Date de demande</div>
          <div className="text-xs text-gray-300">{formatDate(leave.added)}</div>
        </div>

        {leave.attachement && (
          <div
            className={
              "flex flex-col" + (leave.attachement ? " cursor-pointer" : "")
            }
            onClick={() => {
              if (leave.attachement)
                window.location = urls.HOST + leave.attachement;
            }}
          >
            <div className="text-sm mb-3 mt-7">Piece Jointe</div>

            <div className="flex items-center gap-5 bg-black p-4 rounded-md">
              <IonIcon name="attach-outline" size="large" color="white" />
              <div className="text-xs text-blue-400 font-medium">
                {" "}
                Tapez ici pour voir la piece jointe{" "}
                <IonIcon name="open" color="white" />
              </div>
            </div>
          </div>
        )}

        {leave.observation !== null && leave.observation.length !== 0 && (
          <>
            <div className="text-sm mb-3 mt-7">Observation</div>

            <div className="gap-x-5 gap-y-5 bg-black p-4 rounded-md">
              <div className="text-xs text-gray-300">{leave.observation}</div>
            </div>
          </>
        )}

        <div className="mt-7">
          {canValidate() && (
            <>
              <div
                className="flex-1 bg-black text-green-700 rounded-md text-center p-2 cursor-pointer mt-3"
                onClick={() => validate("ACCEPTED")}
              >
                Accepter
              </div>
              <div
                className="flex-1 bg-black text-red-600 rounded-md text-center p-2 cursor-pointer mt-3"
                onClick={() => validate("REFUSED")}
              >
                Refuser
              </div>
            </>
          )}

          {leave.approved === "ACCEPTED" && (
            <div
              className="bg-black text-gray-300 rounded-md text-center p-2 cursor-pointer mt-3"
              onClick={() => navigate(`/leave/print/${leave.id}`)}
            >
              Imprimer
            </div>
          )}

          <div
            className="bg-black text-gray-300 rounded-md text-center p-2 cursor-pointer mt-3"
            onClick={() => setIsShown(false)}
          >
            Fermer
          </div>
        </div>
      </>
    );
  };

  return (
    <ModalV2
      is_loading={is_loading}
      set_is_loading={set_is_loading}
      isShown={isShown}
      setIsShown={setIsShown}
      children={<Component />}
    />
  );
};

export default LeaveDetails;
