import React from "react";

export default function Input({
  label,
  onChange = (e) => {},
  onKeyUp = (e) => {},
  initialValue = "",
  placeholder = "",
  onBlur = () => {},
  ref = null,
}) {
  return (
    <div className="text-sm text-white">
      <label className="capitalize">{label}</label>
      <input
        className="px-2 h-10 mt-2 rounded bg-green-700 w-full text-white input"
        onChange={onChange}
        onKeyUp={onKeyUp}
        defaultValue={initialValue}
        placeholder={placeholder}
        onBlur={() => onBlur([])}
        ref={ref}
      />
    </div>
  );
}
