import React, { useState } from "react";
import Calendar from "react-calendar";

import Modalv2 from "./Modalv2";

const ModalDatePicker = ({ date, setDate, isShown, setIsShown, label }) => {
  const Component = () => {
    return (
      <>
        {/* <div className="text-center font-medium text-xl mb-3 text-white">
          {label}
        </div> */}
        <Calendar
          onChange={(date) => {
            setIsShown(false);
            setDate(date);
          }}
          value={date}
          className="bg-white mx-auto text-black"
        />

        <div
          className="bg-green-700 text-white rounded-md text-center p-2 cursor-pointer mt-3"
          onClick={() => setIsShown(false)}
        >
          Fermer
        </div>
      </>
    );
  };

  return (
    <Modalv2
      isShown={isShown}
      setIsShown={setIsShown}
      children={<Component />}
    />
  );
};

export default ModalDatePicker;
