import React from "react";
import Select from "react-select";

const select_style = {
  control: (baseStyles, state) => ({
    ...baseStyles,
    backgroundColor: "green",
    color: "#3a7e44",
    borderRadius: "4px",
    border: "1px solid green",
  }),
  singleValue: (baseStyles, state) => ({
    ...baseStyles,
    color: "white",
  }),

  option: (base, { isSelected }) => ({
    ...base,
    backgroundColor: isSelected && "#164e63",
    "&:hover": {
      backgroundColor: "#164e63",
    },
  }),
  menu: (baseStyles, state) => ({
    ...baseStyles,
    backgroundColor: "#111827",
    borderRadius: "4px",
  }),
  placeholder: (baseStyles, state) => ({
    ...baseStyles,
    color: "white",
  }),
  input: (provided) => ({
    ...provided,
    color: "white", // Couleur du texte lorsque sélectionné ou saisi
  }),
};

export default function Selectv2({
  label,
  placeholder,
  options,
  onChange,
  className,
  multiple = false,
}) {
  return (
    <div className="flex flex-col flex-1 text-sm text-gray-200 gap-3">
      <label className="capitalize">{label}</label>
      <Select
        multiple={multiple}
        className={className}
        styles={select_style}
        closeMenuOnSelect={true}
        placeholder={placeholder}
        options={options}
        onChange={onChange}
      />
    </div>
  );
}
