
export const fetchData = async (url, data_state, loading_state) => {
  // Setting Loading State
  loading_state(true);
  
  fetch(url, {
    headers: {
      'Authorization': 'token 28d559aa7f12e4dc1383f764117bfbefcb67ce4b',
    }
  }).then((response) => {
    if (response.status === 200)
      return response.json();
    throw Error()
  }).then((data) => {
    data_state(data);
    loading_state(false);
  }).catch((error) => setTimeout(() => fetchData(url, data_state, loading_state), 3000))
};
