import React from "react";

import IonIcon from "@reacticons/ionicons";

export default function Input({
  label,
  onChange = (e) => {},
  value = undefined,
  onKeyUp = (e) => {},
  initialValue = "",
  placeholder = "",
  onBlur = () => {},
  ref = null,
}) {
  return (
    <div className="text-sm text-white">
      <label className="capitalize">{label}</label>
      <label className="flex mt-3 bg-green-700 p-3 rounded-md w-full cursor-pointer">
        {value ? (
          <div className="flex items-center gap-2 text-white">
            <IonIcon size="large" name="checkmark" />
            Votre fichier est prêt
          </div>
        ) : (
          <div className="flex items-center gap-2 text-white">
            <IonIcon size="large" name="attach" />
            Tapez ici pour choisir un Fichier
          </div>
        )}
        <input
          type="file"
          className="hidden"
          onChange={onChange}
          onKeyUp={onKeyUp}
          defaultValue={initialValue}
          placeholder={placeholder}
          onBlur={() => onBlur([])}
          ref={ref}
        />
      </label>
      <div
        className="d-flex align-items-center"
        style={{ backgroundColor: "white" }}
      >
        <p className="m-0 mr-2" style={{ color: "green" }}>
          Veuillez cliquer sur l'icône <IonIcon size="large" name="attach" />{" "}
          pour sélectionner un justificatif | الرجاء الضغط على
          <IonIcon size="large" name="attach" /> لإضافة الورقة الثبوتية
        </p>
      </div>
    </div>
  );
}
